exercise.solution:
const prices = [5, 12, 8, 20, 3, 18];

// 1. Add 15 to the end
prices.push(15);

// 2. Keep only prices above 10
const expensive = prices.filter(price => price > 10);

// 3. Apply a 10% discount
const discounted = expensive.map(price => price * 0.9);

console.log(discounted);
// [ 10.8, 18, 16.2, 13.5 ]
